* CONS -- consumer demo (reads one item per ENTER via implicit cursor).
MAP CONS1 SIZE 24x80
  FIELD AT 0,0  LEN 24 PROT BRIGHT COLOR=BLUE   "TS queue consumer (CONS)"
  FIELD AT 0,60 LEN 5  PROT COLOR=BLUE          "TERM="
  INPUT TERMID  AT 0,65 LEN 8  PROT COLOR=BLUE
  FIELD AT 4,0  LEN 6  PROT                     "Queue:"
  INPUT QNAME   AT 4,8  LEN 16 UNDERSCORE COLOR=GREEN
  STOP          AT 4,25
  FIELD AT 6,0  LEN 12 PROT COLOR=BLUE          "Last item :"
  INPUT LASTITEM AT 6,13 LEN 12 PROT BRIGHT COLOR=GREEN
  FIELD AT 8,0  LEN 12 PROT COLOR=BLUE          "Last payload:"
  INPUT LASTPAY AT 8,14 LEN 60 PROT BRIGHT COLOR=GREEN
  FIELD AT 10,0 LEN 12 PROT COLOR=BLUE          "Reads (this):"
  INPUT NREAD   AT 10,14 LEN 10 PROT BRIGHT COLOR=GREEN
  INPUT MSG     AT 18,0 LEN 78 PROT BRIGHT COLOR=RED
  FIELD AT 22,0 LEN 60 PROT COLOR=BLUE          "ENTER=Read  PF4=DeleteQ  PF5=Rewind  PF3=Exit"
  CURSOR        AT QNAME
ENDMAP
